import{_ as e,o as a,c as l,a3 as r}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"世界书条目管理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/worldbook/entry-management.md","filePath":"user-guide/tools/llm-chat/worldbook/entry-management.md","lastUpdated":1778239080000}'),n={name:"user-guide/tools/llm-chat/worldbook/entry-management.md"};function o(s,t,i,d,g,h){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="世界书条目管理" tabindex="-1">世界书条目管理 <a class="header-anchor" href="#世界书条目管理" aria-label="Permalink to &quot;世界书条目管理&quot;">​</a></h1><p>世界书由多个条目 (Entry) 组成。每个条目都代表一段特定的背景知识或规则。</p><h2 id="_1-条目编辑器" tabindex="-1">1. 条目编辑器 <a class="header-anchor" href="#_1-条目编辑器" aria-label="Permalink to &quot;1. 条目编辑器&quot;">​</a></h2><p>在世界书管理器中选择一个库，即可看到条目列表。点击条目可进入详细编辑器：</p><h3 id="_1-1-基本信息" tabindex="-1">1.1 基本信息 <a class="header-anchor" href="#_1-1-基本信息" aria-label="Permalink to &quot;1.1 基本信息&quot;">​</a></h3><ul><li><strong>UID</strong>: 条目的唯一编号，方便内部引用。</li><li><strong>备注 (Comment)</strong>: 用于记录该条目的简要描述（如“主角的佩剑设定”），不会发送给 LLM。</li><li><strong>内容 (Content)</strong>: 条目被触发时实际注入到上下文中的文本。</li></ul><h3 id="_1-2-触发规则" tabindex="-1">1.2 触发规则 <a class="header-anchor" href="#_1-2-触发规则" aria-label="Permalink to &quot;1.2 触发规则&quot;">​</a></h3><ul><li><strong>主要关键词 (Key)</strong>: 触发该条目的核心词汇。支持多个词，用逗号分隔。</li><li><strong>次要关键词 (Key Secondary)</strong>: 可选。用于建立复杂的触发逻辑（如：只有当出现“剑”且同时出现“亚瑟”时才触发）。</li><li><strong>匹配选项</strong>: <ul><li><strong>大小写敏感</strong>: 是否区分英文大小写。</li><li><strong>全词匹配</strong>: 是否只匹配独立的单词（防止“apple”匹配到“pineapple”）。</li><li><strong>逻辑组合</strong>: AND_ANY / NOT_ALL / NOT_ANY / AND_ALL 等，控制主次关键词的逻辑关系。</li></ul></li></ul><h3 id="_1-3-常量条目-constant" tabindex="-1">1.3 常量条目 (Constant) <a class="header-anchor" href="#_1-3-常量条目-constant" aria-label="Permalink to &quot;1.3 常量条目 (Constant)&quot;">​</a></h3><p>将 <code>constant</code> 设置为 <code>true</code> 后，该条目将<strong>始终被注入</strong>到上下文中，不再依赖关键词匹配。这适用于那些必须始终存在的全局设定。</p><h2 id="_2-注入配置" tabindex="-1">2. 注入配置 <a class="header-anchor" href="#_2-注入配置" aria-label="Permalink to &quot;2. 注入配置&quot;">​</a></h2><p>你可以精确控制条目注入到提示词中的位置：</p><table tabindex="0"><thead><tr><th style="text-align:left;">位置</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Before Character</strong></td><td style="text-align:left;">插入在所有 Agent 角色定义之前。</td></tr><tr><td style="text-align:left;"><strong>After Character</strong></td><td style="text-align:left;">插入在角色定义之后、对话历史之前。</td></tr><tr><td style="text-align:left;"><strong>Before AN</strong></td><td style="text-align:left;">插入在作者备注 (Author&#39;s Note) 之前。</td></tr><tr><td style="text-align:left;"><strong>After AN</strong></td><td style="text-align:left;">插入在作者备注之后。</td></tr><tr><td style="text-align:left;"><strong>Depth (深度)</strong></td><td style="text-align:left;">插入到对话历史的指定深度位置（例如倒数第 5 条消息处）。</td></tr></tbody></table><h2 id="_3-高级控制" tabindex="-1">3. 高级控制 <a class="header-anchor" href="#_3-高级控制" aria-label="Permalink to &quot;3. 高级控制&quot;">​</a></h2><ul><li><strong>概率触发</strong>: 设置一个 0-100% 的概率，让条目随机出现，增加对话的不可预测性。</li><li><strong>粘性激活 (Sticky)</strong>: 触发一次后，强制在后续 N 条消息中保持激活状态。</li><li><strong>冷却时间 (Cooldown)</strong>: 激活后，在接下来的 N 条消息内禁止再次触发。</li><li><strong>分组权重</strong>: 将多个条目分配到同一个组（Group），并设置不同的权重，实现同类设定间的竞争或随机选择。</li></ul><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./scanning-strategy">扫描策略与 Agent 关联</a></li><li><a href="./../context-pipeline/analyzer">上下文分析器</a> — 实时查看条目匹配状态</li></ul>',18)])])}const _=e(n,[["render",o]]);export{u as __pageData,_ as default};
